					SET MILITIMEWORK = DATEDIFF(millisecond, DATEIMEOFFSET_CHECKIN, DATEIMEOFFSETStartLunch ) + DATEDIFF(millisecond, DATEIMEOFFSETEndLunch, DATEIMEOFFSET_CHECKOUT )
