-- ===== Function: [dbo].[WorkingTime_Get_WorkingTime_Times] =====
-- ─── FUNCTION: workingtime_get_workingtime_times ───────────────────────────────
DROP FUNCTION IF EXISTS public.workingtime_get_workingtime_times(integer);
CREATE OR REPLACE FUNCTION public.workingtime_get_workingtime_times(
    userno integer
) RETURNS TABLE(
    workingno integer,
    checktime timestamp without time zone,
    timetype integer,
    timeoffset double precision
)
-- TODO: TOP was preserved as comment; add LIMIT manually
-- TODO: DATEADD was not fully converted; use interval arithmetic
AS $function$
#variable_conflict use_column
DECLARE
    lastchecktype integer;
    lastcheckin timestamp without time zone;
    lastcheckout timestamp without time zone;
    temp_workingno integer;
    temp_checktime timestamp without time zone;
    temp_timetype integer;
    temp_timeoffset double precision;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


















	SELECT CountCheck = COUNT(WorkingNo) 
		FROM WorkingTime_Times 
		WHERE UserNo = workingtime_get_workingtime_times.userno 
			AND  CONVERT(varchar(10), public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), 112) = WorkingDay

	IF CountCheck = 0
	BEGIN
		RETURN QUERY
		SELECT /* TOP 1 */ LastCheckType = TimeType, startDate =  public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)
			FROM WorkingTime_Times
			  where UserNo = workingtime_get_workingtime_times.userno 
				AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) = 
					(SELECT MAX(public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)) AS max_date FROM WorkingTime_Times 
						WHERE UserNo = workingtime_get_workingtime_times.userno
							AND TimeType IN (1,3)
							AND CONVERT(INT, CONVERT(VARCHAR(10), public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), 112)) <= CONVERT(INT, WorkingDay) AND Provider IN (1,2,3,4,9))
			  ORDER BY WorkingNo DESC

		SET startDate = DATEADD(SECOND,1, startDate)
		SET endDate =  DATEADD(HOUR,TimeOutCheckIn, startDate)
		
		IF LastCheckType = 1
		BEGIN
			RETURN QUERY
			SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
				FROM WorkingTime_Times
				WHERE UserNo = workingtime_get_workingtime_times.userno
					AND TimeType IN (1,3)
					AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN startDate AND endDate
				ORDER BY CheckTime 
				
			IF(temp_TimeType = 3)
				BEGIN;
					INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 00:00:00'), LastCheckType, temp_TimeOffset);
					INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 23:59:59'), temp_TimeType, temp_TimeOffset)
				END
		END
	END
	ELSE
	BEGIN;
		INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset)
		RETURN QUERY
		SELECT WorkingNo, public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) AS CheckTime, TimeType, TimeOffset
			FROM WorkingTime_Times
			WHERE UserNo = workingtime_get_workingtime_times.userno 
				AND TimeType IN (1,3)
				AND  CONVERT(DATE,public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)) = WorkingDay

		SELECT CountReturn = COUNT(WorkingNo) FROM ReturnDepartments
		IF CountReturn = 1
		BEGIN
			SELECT MaxCheckType = TimeType, startDate =  CheckTime FROM ReturnDepartments 
				WHERE CheckTime = (SELECT MAX(CheckTime) AS CheckTime FROM ReturnDepartments)

			IF MaxCheckType = 1
				BEGIN

					SET startDate = DATEADD(SECOND,1, startDate)
					SET endDate = DATEADD(HOUR,TimeOutCheckIn, startDate)

					RETURN QUERY
					SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
						FROM WorkingTime_Times
						WHERE UserNo = workingtime_get_workingtime_times.userno 
							AND TimeType IN (1,3)
							AND  public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN startDate AND endDate
						ORDER BY CheckTime 
					IF(temp_TimeType = 3);
						INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 23:59:59'), temp_TimeType, temp_TimeOffset)

				END
				ELSE IF MaxCheckType = 3
				BEGIN
					SET startDate = DATEADD(SECOND,-1, startDate)
					SET endDate = DATEADD(HOUR,-TimeOutCheckIn, startDate)

					RETURN QUERY
					SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
						FROM WorkingTime_Times
						WHERE UserNo = workingtime_get_workingtime_times.userno 
							AND TimeType IN (1,3)
							AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN endDate AND startDate
						ORDER BY CheckTime DESC
					IF temp_TimeType = 1
					BEGIN;
						INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 00:00:00'), temp_TimeType, temp_TimeOffset)
					END
					ELSE IF temp_TimeType <> 3
					BEGIN
						SELECT LastCheckIn = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeOffset = TimeOffset
						FROM WorkingTime_Times
						WHERE UserNo = workingtime_get_workingtime_times.userno 
							AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) = 
								(SELECT MAX(public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)) AS max_date FROM WorkingTime_Times 
									WHERE UserNo = workingtime_get_workingtime_times.userno 
										AND CONVERT(VARCHAR(10), public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), 112) = CONVERT(VARCHAR(10), temp_CheckTime, 112)
										AND TimeType = 1 
										AND Provider in (1,2,3,4,9))
						
						SELECT LastCheckOut = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)
						FROM WorkingTime_Times
						WHERE UserNo = workingtime_get_workingtime_times.userno 
							AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) = 
								(SELECT MAX(public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime)) AS max_date FROM WorkingTime_Times 
									WHERE UserNo = workingtime_get_workingtime_times.userno 
										AND CONVERT(VARCHAR(10), public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), 112) = CONVERT(VARCHAR(10), temp_CheckTime, 112)
										AND TimeType = 3 
										AND Provider IN (1,2,3,4,9))

						IF LastCheckIn > LastCheckOut
						BEGIN;
							INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
								VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 00:00:00'), 1 , temp_TimeOffset)	
						END
					END
				
				END
		END
		ELSE IF CountReturn>1
		BEGIN
			SELECT MaxCheckType = TimeType, startDate =  CheckTime FROM ReturnDepartments 
				WHERE CheckTime = (SELECT MAX(CheckTime) AS CheckTime FROM ReturnDepartments)

			IF MaxCheckType = 1
			BEGIN
				SET startDate = DATEADD(SECOND,1, startDate)
				SET endDate = DATEADD(HOUR,TimeOutCheckIn, startDate)

				RETURN QUERY
				SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
					FROM WorkingTime_Times
					WHERE UserNo = workingtime_get_workingtime_times.userno 
						AND TimeType IN (1,3)
						AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN startDate AND endDate
					ORDER BY CheckTime 

				IF(temp_TimeType = 3);
					INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 23:59:59'), 3, temp_TimeOffset)

			END
			ELSE IF MaxCheckType <> 3
			BEGIN
				SELECT LastCheckIn = CheckTime, temp_TimeOffset = TimeOffset
				FROM ReturnDepartments
					WHERE CheckTime = (SELECT MAX(CheckTime) AS CheckTime FROM ReturnDepartments WHERE TimeType = 1)

				SELECT LastCheckOut = CheckTime
				FROM ReturnDepartments
					WHERE CheckTime = (SELECT MAX(CheckTime) AS CheckTime FROM ReturnDepartments WHERE TimeType = 3)

				IF LastCheckIn > LastCheckOut
				BEGIN
					SET startDate = DATEADD(SECOND,1, LastCheckIn)
					SET endDate =  DATEADD(HOUR,TimeOutCheckIn, startDate)

					RETURN QUERY
					SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
					FROM WorkingTime_Times
					WHERE UserNo = workingtime_get_workingtime_times.userno 
						AND TimeType IN (1,3)
						AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN startDate AND endDate
					ORDER BY CheckTime 

					IF(temp_TimeType = 3)
					BEGIN;
						INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 23:59:59'), 3 , temp_TimeOffset)
					END
				END
			END

			SELECT MinCheckType = TimeType, startDate =  CheckTime FROM ReturnDepartments 
				WHERE CheckTime = (SELECT MIN(CheckTime) AS CheckTime FROM ReturnDepartments)
			IF MinCheckType = 3
			BEGIN
				SET startDate = DATEADD(SECOND,-1, startDate)
				SET endDate = DATEADD(HOUR,-TimeOutCheckIn, startDate)

				RETURN QUERY
				SELECT /* TOP 1 */ temp_WorkingNo = WorkingNo, temp_CheckTime = public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime), temp_TimeType = TimeType, temp_TimeOffset = TimeOffset
					FROM WorkingTime_Times
					WHERE UserNo = workingtime_get_workingtime_times.userno
						AND TimeType IN (1,3)
						AND public."AddWorkingDayTimes"(TimeOffset,WorkingDay,CheckTime) BETWEEN endDate AND startDate
					ORDER BY CheckTime DESC

				IF temp_TimeType = 1
				BEGIN;
					INSERT INTO ReturnDepartments (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (temp_WorkingNo, DATEADD(HOUR,0, WorkingDay || ' 00:00:00'), 1, temp_TimeOffset)
				END
			END
		END
	END
	RETURN;
END;
$function$
LANGUAGE plpgsql;
-- TODO: Owner mapping skipped. Target role postgres not verified.

-- ===== Function: [dbo].[WorkingTime_TimeWorkForUser_Funtion] =====
-- ─── FUNCTION: workingtime_timeworkforuser_funtion ───────────────────────────────
DROP FUNCTION IF EXISTS public.workingtime_timeworkforuser_funtion(integer);
CREATE OR REPLACE FUNCTION public.workingtime_timeworkforuser_funtion(
    userno integer
) RETURNS character varying
-- TODO: DATEADD was not fully converted; use interval arithmetic
AS $function$
DECLARE
    result character varying;
    workingtime double precision;
    starttimework timestamp without time zone;
    endtimework timestamp without time zone;
    endtimeworkingday character varying;
    dendtimeworkingday timestamp without time zone;
    checklunchstatus boolean;
    checkinstatus boolean;
    checkoutstatus boolean;
    workingno integer;
    timetype integer;
    timeoffset double precision;
    stimeoffset double precision;
    checktime timestamp without time zone;
    timeutc character varying;
    dateutc character varying;
    datetimeutc timestamp without time zone;
    datetimeutcfloat double precision;
    endtimeworkingdayfloat double precision;
    workingtime_cursor cursor;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN















	-- Get datetime Utc





	SET DateTimeUTC = GETUTCDATE()

	SET DateTimeUTCFloat = cast(DateTimeUTC AS FLOAT)
	SET DateTimeUTCFloat = DateTimeUTCFloat - FLOOR(DateTimeUTCFloat)

	SET TimeUTC = REPLACE(public."ConvertWorkingTimeWorkToTime"(DateTimeUTCFloat),':','')

	--- end get datetime utc


	SET EndTimeWorkingDay = (SELECT SettingValue FROM public."WorkingTime_Settings" where SettingNo = 2) || '00'
	SET DEndTimeWorkingDay = LEFT(EndTimeWorkingDay,2) || ':' || SUBSTRING(EndTimeWorkingDay,3,2) || ':' || RIGHT(EndTimeWorkingDay,2)
	SET EndTimeWorkingDayFloat = cast(DEndTimeWorkingDay AS FLOAT)

	SET CheckLunchStatus = CAST((SELECT SettingValue FROM public."WorkingTime_Settings" where SettingNo = 6) AS BIT)

	SET CheckInStatus =  0
	SET CheckOutStatus =  0
	SET Workingtime = 0
	SET WorkingTime_Cursor = CURSOR FAST_FORWARD
	FOR
		SELECT WorkingNo, CheckTime, TimeType, TimeOffset
		FROM WorkingTime_Get_WorkingTime_Times(UserNo, WorkingDay)
		ORDER BY WorkingNo

	OPEN WorkingTime_Cursor

	FETCH NEXT FROM WorkingTime_Cursor

	INTO WorkingNo, CheckTime, TimeType, TimeOffset

	WHILE @FETCH_STATUS = 0
	   BEGIN
			IF CheckLunchStatus = 0
				BEGIN
					IF TimeType = 1 AND CheckInStatus = 0   -- Check in 
						BEGIN 
						   SET sTimeOffset = TimeOffset
						   SET StartTimeWork = (public."ConverToUtcTime"(TimeOffset, CheckTime))
						   SET EndTimeWork = ''
						   SET CheckInStatus = 1
						   SET CheckOutStatus = 0
						END
					--ELSE IF TimeType = 1 AND CheckInStatus = 1 AND CheckOutStatus = 0  --  Check in multiple times
					--	BEGIN
					--	   SET sTimeOffset = TimeOffset
					--	   SET StartTimeWork = CheckTime
					--	END
					ELSE IF TimeType = 3 AND CheckInStatus = 1 -- Check Out times
						BEGIN 
						   SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset, CheckTime))
						   SET CheckInStatus = 0
						   SET CheckOutStatus = 1
						   SET Workingtime =  Workingtime || (public."WorkingTimeWorks"(StartTimeWork, EndTimeWork))
						END
					ELSE IF TimeType = 3 AND CheckInStatus = 0 AND CheckOutStatus = 1 -- Check Out multiple times
						BEGIN 
						   SET StartTimeWork = EndTimeWork
						   SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset, CheckTime))
						   SET Workingtime =  Workingtime || (public."WorkingTimeWorks"(StartTimeWork, EndTimeWork))
						END
					
				END
			ELSE IF CheckLunchStatus = 1
				BEGIN
					IF TimeType = 1 AND CheckInStatus = 0   -- Check in 
						BEGIN
						   SET sTimeOffset = TimeOffset
						   SET StartTimeWork = (public."ConverToUtcTime"(TimeOffset,(public."WorkingTimeWorks_CheckIn_Lunch"(CheckTime, TimeType))))
						   SET EndTimeWork = ''
						   SET CheckInStatus = 1
						   SET CheckOutStatus = 0
						END
					--ELSE IF TimeType = 1 AND CheckInStatus = 1 AND CheckOutStatus = 0  --  Check in multiple times
					--	BEGIN 
					--	    SET sTimeOffset = TimeOffset
					--		SET StartTimeWork = public."WorkingTimeWorks_CheckIn_Lunch"(CheckTime, TimeType) 
					--	END
					ELSE IF TimeType = 3 AND CheckInStatus = 1 -- Check Out times
						BEGIN 
							
						   SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset,(public."WorkingTimeWorks_CheckIn_Lunch"(CheckTime, TimeType))))
						   SET CheckInStatus = 0
						   SET CheckOutStatus = 1
						   SET Workingtime =  Workingtime || (public."WorkingTimeWorksAddLunch"(StartTimeWork, EndTimeWork, TimeOffset))
						END
					ELSE IF TimeType = 3 AND CheckInStatus = 0 AND CheckOutStatus = 1 -- Check Out multiple times
						BEGIN
						   SET StartTimeWork = EndTimeWork 
						   SET EndTimeWork =(public."ConverToUtcTime"(TimeOffset, (public."WorkingTimeWorks_CheckIn_Lunch"(CheckTime, TimeType))))
						   SET Workingtime =  Workingtime || (public."WorkingTimeWorksAddLunch"(StartTimeWork, EndTimeWork, TimeOffset))
						END
				END
		  FETCH NEXT FROM WorkingTime_Cursor
		  INTO WorkingNo, CheckTime, TimeType, TimeOffset
	   END;
	CLOSE WorkingTime_Cursor
	DEALLOCATE WorkingTime_Cursor

	SET DateUTC =  CONVERT (VARCHAR (20), DATEADD(hour, sTimeOffset, DateTimeUTC), 112)

	IF DateUTC = WorkingDay
		BEGIN
			IF CheckLunchStatus = 0
				BEGIN 
					IF CheckInStatus = 1 AND CheckOutStatus = 0
						BEGIN
							IF EndTimeWorkingDayFloat <= DateTimeUTCFloat
								BEGIN
									SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset,public."AddWorkingDayTimes"(TimeOffset, WorkingDay, EndTimeWorkingDay)))
								END
							ELSE
								BEGIN
									SET EndTimeWork =(public."ConverToUtcTime"(TimeOffset, (public."WorkingTimeWorks_CheckIn_Lunch"(public."AddWorkingDayTimes"(TimeOffset, WorkingDay ,TimeUTC), 3))))
								END
							SET Workingtime =  Workingtime || (public."WorkingTimeWorks"(StartTimeWork, EndTimeWork))
						END
				END
			ELSE IF CheckLunchStatus = 1
				BEGIN
					IF CheckInStatus = 1 AND CheckOutStatus = 0
						BEGIN
							IF EndTimeWorkingDayFloat <= DateTimeUTCFloat
								BEGIN
									SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset,public."AddWorkingDayTimes"(TimeOffset, WorkingDay, EndTimeWorkingDay)))
								END
							ELSE
								BEGIN
									SET EndTimeWork = (public."ConverToUtcTime"(TimeOffset,(public."WorkingTimeWorks_CheckIn_Lunch"(public."AddWorkingDayTimes"(TimeOffset, WorkingDay, TimeUTC), 3))))
								END
								
							SET Workingtime =  Workingtime || (public."WorkingTimeWorksAddLunch"(StartTimeWork, EndTimeWork, TimeOffset))
						END
				END
		END
	ELSE  IF DateUTC > WorkingDay
		BEGIN
			IF CheckLunchStatus = 0
				BEGIN
					IF CheckInStatus = 1 AND CheckOutStatus = 0
					BEGIN
						SET EndTimeWork =  (public."ConverToUtcTime"(TimeOffset,DATEADD(day, (WorkingDay::date - 0::date),  CONVERT(CHAR(8), LEFT(EndTimeWorkingDay,2) || ':' || SUBSTRING(EndTimeWorkingDay,3,2) || ':' || RIGHT(EndTimeWorkingDay,2)))))
						SET Workingtime =  Workingtime || (public."WorkingTimeWorks"(StartTimeWork, EndTimeWork))
					END
				END
			ELSE IF CheckLunchStatus = 1
				BEGIN
				IF CheckInStatus = 1 AND CheckOutStatus = 0
					BEGIN
						SET EndTimeWork =  (public."ConverToUtcTime"(TimeOffset,DATEADD(day, (WorkingDay::date - 0::date),  CONVERT(CHAR(8), LEFT(EndTimeWorkingDay,2) || ':' || SUBSTRING(EndTimeWorkingDay,3,2) || ':' || RIGHT(EndTimeWorkingDay,2)))))
						SET Workingtime =  Workingtime || (public."WorkingTimeWorksAddLunch"(StartTimeWork, EndTimeWork, TimeOffset))
					END
				END
		END
	  SET RESULT = public."ConvertWorkingTimeWorkToTime"(Workingtime)

	  RETURN RESULT;
END;
$function$
LANGUAGE plpgsql;
