	UPDATE BW SET BW.Sort=(SELECT /* /* TOP 1 */ */T.Sort FROM WidgetTemp T WHERE BW.No <>T.No),BW.ModUserNo= board_downmultilwidget.userno,BW.ModDate=NOW()
