CREATE OR REPLACE FUNCTION public.board_upmultiwidget(
    IN userno integer,
    IN boardno integer
) RETURNS void
AS $function$
DECLARE
    sorttemp integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	CREATE TEMP TABLE WidgetTemp AS SELECT Sort INTO sorttemp FROM Board_MultiBoardWidget WHERE  BoardNo = board_upmultiwidget.boardno AND  IsDelete= FALSE
	SELECT /* /* TOP 2 */ */ No,Sort FROM Board_MultiBoardWidget
	WHERE  IsDelete= FALSE AND Sort>=SortTemp
	ORDER BY Sort ASC;
	UPDATE BW SET BW.Sort=(SELECT /* /* TOP 1 */ */T.Sort FROM WidgetTemp T WHERE BW.No <>T.No),BW.ModUserNo= board_upmultiwidget.userno,BW.ModDate=NOW()
	FROM Board_MultiBoardWidget BW
	INNER JOIN WidgetTemp T ON T.No=BW.No;
END;
