			AND		Plot is null 
			AND		B.UseYn = 'Y'
			AND		C.OrgCd = bslg_getdeptlog.deptid
			AND		D.ClassCd = 'C001'
			order by D.CommCd,A.UserID,A.RegDate
		END IF;
	ELSIF Lang = '3' THEN
			RETURN QUERY
			SELECT	B.UserNm3 usernm,D.Etc2Cd commcd,A.UserID,RegDate,Content1, Content2, att1, att2, att3, att4, att5, Title
			FROM	BSLG_Log A
			inner join CMONUsers B
