-- ===== Procedure: [dbo].[BSLG_SpAuthUserCnt] =====
-- ─── PROCEDURE→FUNCTION: bslg_spauthusercnt ───────────────────────────────
-- NOTE: SQL Server stored procedure converted to PostgreSQL function.
-- TODO: Review converted output — stored procedure semantics differ; test before use in production.
-- TODO: replace SETOF record — procedure returns results; add RETURNS TABLE(col type, ...) manually
-- TODO: procedure contains result-returning SELECT; replace SETOF record with correct column types
DROP FUNCTION IF EXISTS public.bslg_spauthusercnt(character varying, character varying, character varying, character varying, character varying, character varying);
CREATE OR REPLACE FUNCTION public.bslg_spauthusercnt(
    IN orgcd character varying,
    IN grpcd character varying,
    IN useyn character varying,
    IN lang character varying,
    IN serach1 character varying,
    IN serach2 character varying
) RETURNS SETOF record
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
		
	RETURN QUERY
	SELECT COUNT(*)
		
	FROM 
		CMONUsers 		A
	LEFT OUTER JOIN CMONCommCd	B	
	ON	A.PosFg1 = B.CommCd AND B.ClassCd = 'C001'
	WHERE
		 A.UseYn ILIKE UseYn
	AND 
	(	
		( OrgCd1 ILIKE OrgCd OR OrgCd2 ILIKE OrgCd OR OrgCd3 ILIKE OrgCd)
		OR 
		( OrgCd1 IN (SELECT OrgCd FROM  public."COMNGetOrganChild"(OrgCd)))
	)
	--AND public."CMONGetOrganGroup"(OrgCd1) = GrpCd
	AND A.UserNm1 ILIKE Serach1
	AND A.UserId ILIKE Serach2;
END;
$function$
LANGUAGE plpgsql;
-- TODO: Owner mapping skipped. Target role postgres not verified.

-- ===== Procedure: [dbo].[BSLG_SpAuthUserList] =====
-- ─── PROCEDURE→FUNCTION: bslg_spauthuserlist ───────────────────────────────
-- NOTE: SQL Server stored procedure converted to PostgreSQL function.
-- TODO: Review converted output — stored procedure semantics differ; test before use in production.
-- TODO: replace SETOF record — procedure returns results; add RETURNS TABLE(col type, ...) manually
-- TODO: procedure contains result-returning SELECT; replace SETOF record with correct column types
DROP FUNCTION IF EXISTS public.bslg_spauthuserlist(character varying);
CREATE OR REPLACE FUNCTION public.bslg_spauthuserlist(
    IN userid character varying
) RETURNS SETOF record
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	RETURN QUERY
	SELECT 
	B.SharedUserId  as Code,
	U.Name as Name
	, COALESCE(D.Name,'') as OrgNm
	, COALESCE(P.Name,'') as PosNm
	FROM BSLG_SpAuthInfo B
	LEFT JOIN Organization_Users U ON U.UserID = B.SharedUserId and B.UserofDepart = 'user'
	--and B.UserofDepart = 'depart'
	LEFT JOIN Organization_BelongToDepartment BE on BE.UserNo = U.UserNo and BE.IsDefault = TRUE
	LEFT JOIN Organization_Departments D ON D.DepartNo = B.SharedDepartNo or D.DepartNo = BE.DepartNo
	LEFT JOIN Organization_Positions P ON P.PositionNo = BE.PositionNo
	where UserofDepart = 'user'
	AND B.UserId = bslg_spauthuserlist.userid

	union

	RETURN QUERY
	SELECT 
	U.UserID as Code,
	U.Name as Name
	, COALESCE(D.Name,'') as OrgNm
	, COALESCE(P.Name,'') as PosNm
	FROM BSLG_SpAuthInfo B
	LEFT JOIN Organization_BelongToDepartment BE on BE.DepartNo = B.SharedDepartNo and BE.IsDefault = TRUE
	LEFT JOIN Organization_Users U ON U.UserNo = BE.UserNo
	LEFT JOIN Organization_Departments D ON D.DepartNo = B.SharedDepartNo or D.DepartNo = BE.DepartNo
	LEFT JOIN Organization_Positions P ON P.PositionNo = BE.PositionNo
	where UserofDepart = 'depart'
	AND B.UserId = bslg_spauthuserlist.userid;
END;
$function$
LANGUAGE plpgsql;
-- TODO: Owner mapping skipped. Target role postgres not verified.

-- ===== Procedure: [dbo].[BSLG_SpList] =====
-- ─── PROCEDURE→FUNCTION: bslg_splist ───────────────────────────────
-- NOTE: SQL Server stored procedure converted to PostgreSQL function.
-- TODO: Review converted output — stored procedure semantics differ; test before use in production.
-- TODO: replace SETOF record — procedure returns results; add RETURNS TABLE(col type, ...) manually
-- TODO: procedure contains result-returning SELECT; replace SETOF record with correct column types
DROP FUNCTION IF EXISTS public.bslg_splist(character varying, character varying, character varying, character varying, character varying, character varying);
CREATE OR REPLACE FUNCTION public.bslg_splist(
    IN userid character varying,
    IN startdate character varying,
    IN enddate character varying,
    IN langindex character varying,
    IN title character varying,
    IN content character varying
) RETURNS SETOF record
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	
	RETURN QUERY
	SELECT	bl.UserID, RegDate, Content1, Content2, att1, att2, att3, att4, att5, COALESCE(Title, '제목') Title
			, CASE LangIndex When '1' Then cu.UserNm1
							  When '2' Then cu.UserNm2
							  When '3' Then cu.UserNm3
			  ELSE cu.UserNm1
			  END As UserNm
			, public."CMONGetOrganNm"(cu.OrgCd1, LangIndex) As OrgNm
			, public."CMONGetCommCdNm"('C001', cu.PosFg1, LangIndex)  as PosNm
	FROM	CMONUsers cu, BSLG_Log bl
	WHERE	bl.UserID=bslg_splist.userid 
	AND     bl.UserID=cu.UserID
	AND		(RegDate >= bslg_splist.startdate AND RegDate <=  bslg_splist.enddate ) 
	AND		Title ILIKE '%' || Title || '%'
	AND		Content1 ILIKE '%' || Content || '%'
	ORDER BY RegDate;
END;
$function$
LANGUAGE plpgsql;
-- TODO: Owner mapping skipped. Target role postgres not verified.

