	END IF;

	ELSE BEGIN
	
		UPDATE Center_Holidays SET
			ModUserNo = center_updateholidayforsaturdayandsunday.moduserno,
			ModDate = center_updateholidayforsaturdayandsunday.moddate,
			HolidayDate = HolidayDate
		WHERE HolidayNo = HolidayNo

	END;
END;
