	RETURN QUERY
	SELECT * FROM Contact_PublicGroupUser WHERE UserSeq = Seq AND IsDelete= FALSE
	RETURN QUERY
	SELECT * FROM Contact_ShareGroupUser WHERE UserSeq = Seq AND IsDelete= FALSE;
	UPDATE ContactsUser 
	ViewCount := ViewCount+1;
	WHERE Seq = Seq;
END;
