DROP FUNCTION IF EXISTS public.contacts_getuser_sns(integer);
CREATE OR REPLACE FUNCTION public.contacts_getuser_sns(
    IN userseq integer
) RETURNS SETOF record
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT 
