		-- 집팩스
		IF LEN(HomeFax) > 0 THEN;
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				3,
				'FAX',
				HomeFax,
				0
			)
		END IF;
		-- 회사전화
		IF LEN(WorkPhone) > 0 THEN;
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				2,
				'회사',
				WorkPhone,
				0
			)
		END IF;
		-- 회사팩스
		IF LEN(WorkFax) > 0 THEN;
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				3,
				'FAX',
				WorkFax,
				0
			)
		END IF;
		-- 기타전화
		IF LEN(OtherPhone) > 0 THEN;
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				8,
				'기타',
				OtherPhone,
				0
			)
		END IF;
		-- 기타팩스
		IF LEN(OtherFax) > 0 THEN;
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				3,
				'FAX',
				OtherFax,
				0
			)
		END IF;
		-- 기존주소 삭제;
		DELETE FROM ContactsAddress
		WHERE RegUserNo = UserNo
		AND UserSeq = ContactNo
		--집주소
		IF LEN(HomePost) > 0 OR LEN(HomeAddress) > 0 THEN;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				1,
				'집',
				SUBSTRING(HomePost,1,3),
				SUBSTRING(HomePost,4,3),
				HomeAddress,
				0
			)
		END IF;
		--회사주소
		IF LEN(WorkPost) > 0 OR LEN(WorkAddress) > 0 THEN;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				0,
				'회사',
				SUBSTRING(WorkPost,1,3),
				SUBSTRING(WorkPost,4,3),
				WorkAddress,
				0
			)
		END IF;
		--기타주소
		IF LEN(OtherPost) > 0 OR LEN(OtherAddress) > 0 THEN;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				ContactNo,
				8,
				'기타',
				SUBSTRING(OtherPost,1,3),
				SUBSTRING(OtherPost,4,3),
				OtherAddress,
				0
			)
		END IF;
	END IF;
END;
$function$
LANGUAGE plpgsql;
