DROP FUNCTION IF EXISTS public.crewchat_createnotifyuserchatroom(integer, integer);
CREATE OR REPLACE FUNCTION public.crewchat_createnotifyuserchatroom(
    IN userno integer,
    IN joinuserno integer
) RETURNS SETOF record
AS $function$
DECLARE
    roomno integer;
    isone boolean;
    isclosed boolean;
    roomtitle character varying;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN



	RoomNo := (SELECT public."CrewChat_GetOneUserChatRoom"(UserNo, JoinUserNo));
	IF RoomNo > 0 THEN

		-- 본인이 나간 방 일 경우 처리

		IsOne := (SELECT IsOne FROM CrewChat_Rooms WHERE RoomNo = RoomNo);
		IF IsOne = TRUE THEN
			-- 상대방이 나간 상태 일 때

			IsClosed := (SELECT Closed FROM CrewChat_RoomUsers WHERE RoomNo = RoomNo;
							 AND UserNo = crewchat_createnotifyuserchatroom.userno)
							 
			IF IsClosed = TRUE THEN

				-- 나간 상태를 다시 돌려놓는다.;
				UPDATE CrewChat_RoomUsers SET Closed = 0
				WHERE RoomNo = RoomNo AND UserNo = crewchat_createnotifyuserchatroom.userno

			END IF;
								 
		END IF;
		

		RoomTitle := (SELECT RoomTitle FROM CrewChat_RoomUsers WHERE RoomNo = RoomNo AND UserNo=crewchat_createnotifyuserchatroom.userno);
		-- 기존 1:1 채팅방이 존재합니다.
		RETURN QUERY
		SELECT R.RoomNo, R.MakeUserNo, R.ModDate, R.IsOne, RoomTitle AS RoomTitle, U.UserNo, FALSE AS NewRoom
		FROM CrewChat_Rooms R 
		INNER JOIN CrewChat_RoomUsers U ON U.RoomNo = R.RoomNo
		WHERE R.RoomNo = RoomNo
				
	END IF;

	ELSE BEGIN

		-- 기존방이 없습니다. 채팅방을 새로 생성합니다.;
		INSERT INTO CrewChat_Rooms (MakeUserNo, IsOne) VALUES (UserNo, 1)
		
		RoomNo := lastval();
		IF RoomNo > 0 THEN

			-- 방만드는 유저 추가;
			INSERT INTO CrewChat_RoomUsers (RoomNo, UserNo, RoomTitle) VALUES (RoomNo, UserNo, Title)

			-- 상대방 추가;
			INSERT INTO CrewChat_RoomUsers (RoomNo, UserNo, RoomTitle) VALUES (RoomNo, JoinUserNo, Title)

		END IF;
		
		-- 만들어진 방의 기본 정보를 보냅니다.
		RETURN QUERY
		SELECT R.RoomNo, R.MakeUserNo, R.ModDate, R.IsOne, U.RoomTitle, U.UserNo, TRUE AS NewRoom
		FROM CrewChat_Rooms R 
		INNER JOIN CrewChat_RoomUsers U ON U.RoomNo = R.RoomNo
		WHERE R.RoomNo = RoomNo

	END;
END;
$function$
LANGUAGE plpgsql;
