DROP FUNCTION IF EXISTS public.crewchat_insertattachchatmessage(bigint, integer, character varying, integer, integer);
CREATE OR REPLACE FUNCTION public.crewchat_insertattachchatmessage(
    IN roomno bigint,
    IN userno integer,
    IN message character varying,
    IN attachno integer,
    IN type integer
) RETURNS SETOF record
AS $function$
DECLARE
    messageno bigint;
    isone boolean;
    isclosed boolean;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	INSERT INTO CrewChat_Messages (RoomNo, UserNo, Message, Type, AttachNo, RegDate)
	VALUES (RoomNo, UserNo, Message, Type, AttachNo, NOW())
	
	MessageNo := lastval();
	-- 1:1 채팅방 일 때

	IsOne := (SELECT IsOne FROM CrewChat_Rooms WHERE RoomNo = crewchat_insertattachchatmessage.roomno);
	IF IsOne = TRUE THEN
		-- 상대방이 나간 상태 일 때

		IsClosed := (SELECT Closed FROM CrewChat_RoomUsers WHERE RoomNo = crewchat_insertattachchatmessage.roomno;
						 AND UserNo != crewchat_insertattachchatmessage.userno)
						 
		IF IsClosed = TRUE THEN
			-- 나간 상태를 다시 돌려놓는다.;
			UPDATE CrewChat_RoomUsers SET Closed = 0, StartMessageNo=MessageNo 
			WHERE RoomNo = crewchat_insertattachchatmessage.roomno AND UserNo != crewchat_insertattachchatmessage.userno
		END IF;
	END IF;
	
	RETURN QUERY
	SELECT M.MessageNo, M.RoomNo, M.UserNo, 
	(SELECT U.Name FROM Organization_Users U WHERE U.UserNo = M.UserNo) AS UserName, 
	M.Message, M.Type, M.AttachNo, M.RegDate,
	(SELECT COUNT(CheckNo) FROM CrewChat_CheckMessage C 
	WHERE C.RoomNo=M.RoomNo AND C.IsRead = FALSE AND C.MessageNo = M.MessageNo) AS UnreadCount
	FROM CrewChat_Messages M
	WHERE M.MessageNo = MessageNo;
END;
