--*/
		
		--최신버전으로 셋팅하기위한 액숀.		;
		UPDATE	EDMSDOCUMENT
		VERSIONSTATE := '';
		WHERE	WGROUP =(
							SELECT WGROUP  FROM EDMSDOCUMENT WHERE	ID = DOCID
						)

