		UPDATE	EDMSDOCUMENT
		ISDELETE := '';
		,		MODDATE = NOW()
		,		Modifier = edmsreturndoc.userid
		,		VersionState = 'Y'
		WHERE	ID = DOCID	

		RETURN QUERY
		SELECT DOCID;
END;
$function$
