				END IF;
				+ case	when COUNTFLAG	= 'Y'	 then '(' || CONVERT(VARCHAR(80),(SELECT count(P.ID) FROM EDMSPRIVATELIST P WHERE P.FolderID=T.ID ))+')'
									else '' 
